function numTilePossibilities(tiles) {
    const freq = new Array(26).fill(0);
    for (const c of tiles) {
        freq[c.charCodeAt(0) - 'A'.charCodeAt(0)]++;
    }

    function dfs(freq) {
        let result = 0;
        for (let i = 0; i < 26; i++) {
            if (freq[i] > 0) {
                freq[i]--;
                result += 1 + dfs(freq);
                freq[i]++;
            }
        }
        return result;
    }

    return dfs(freq);
}
