public int numTilePossibilities(String tiles) {
    int[] freq = new int[26];
    for (char c : tiles.toCharArray()) {
        freq[c - 'A']++;
    }

    return numTilePossibilities(freq);
}

private int numTilePossibilities(int[] freq) {
    int result = 0;
    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) {
            freq[i]--;
            result += 1 + numTilePossibilities(freq);
            freq[i]++;
        }
    }
    return result;
}
```

